export function ChainSwitcher() {
  const [mounted, setMounted] = useState(false)
  const [activeNetwork, setActiveNetwork] = useState<'Mainnet' | 'Preprod'>('Preprod')

  useEffect(() => {
    setMounted(true)
    const saved = localStorage.getItem('doba_network')
    if (saved === 'Mainnet' || saved === 'Preprod') {
      setActiveNetwork(saved)
    }
  }, [])

  if (!mounted) return null

  const handleNetworkChange = (network: 'Mainnet' | 'Preprod') => {
    if (network === activeNetwork) return
    localStorage.setItem('doba_network', network)
    // Clear connected wallet to prevent using Preprod wallet on Mainnet or vice-versa
    localStorage.removeItem('doba_connected_wallet')
    localStorage.removeItem('doba_auth_data')
    if (typeof window !== 'undefined') {
      globalThis.location?.reload()
    }
  }

  const accentColor = activeNetwork === 'Mainnet' ? '#0033AD' : '#ff5553'

  return (
    <div className="flex items-center gap-2">
      <CardanoLogo accentColor={accentColor} />
      
      <div className="flex items-center bg-midnight/[0.04] dark:bg-white/[0.04] border border-midnight/10 dark:border-white/10 rounded-full p-0.5 relative">
        <button
          type="button"
          onClick={() => handleNetworkChange('Preprod')}
          className={`px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider transition-all duration-300 ${
            activeNetwork === 'Preprod'
              ? 'bg-[#ff5553]/15 text-[#ff5553] shadow-sm'
              : 'text-midnight/70 dark:text-white/40 hover:text-midnight dark:hover:text-white'
          }`}
        >
          Preprod
        </button>
        <button
          type="button"
          onClick={() => handleNetworkChange('Mainnet')}
          className={`px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider transition-all duration-300 ${
            activeNetwork === 'Mainnet'
              ? 'bg-[#0033AD]/15 text-[#0033AD] shadow-sm'
              : 'text-midnight/70 dark:text-white/40 hover:text-midnight dark:hover:text-white'
          }`}
        >
          Mainnet
        </button>
      </div>
    </div>
  )
}
